SELECT COUNT(1)
FROM edu_course_order
WHERE user_id = #{userId}
  AND course_id = #{courseId}
  AND status = 1
  AND deleted = 0

SELECT 
FROM edu_course_order o
WHERE o.deleted = 0

    AND o.order_no LIKE CONCAT('%', #{orderNo}, '%')


    AND o.course_name LIKE CONCAT('%', #{courseName}, '%')


    AND o.status = #{status}


    AND o.create_time >= #{startTime}


    AND o.create_time <= #{endTime}

ORDER BY o.create_time DESC
